function cleanInput(string $key, string $default = ''): string
{
    return trim((string)($_POST[$key] ?? $default));
}

function installerEsc($value): string
{
    return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8');
}

function detectedBaseUrl(): string
{
    $https = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off') || ((int)($_SERVER['SERVER_PORT'] ?? 80) === 443);
    $scheme = $https ? 'https' : 'http';
    $host = $_SERVER['HTTP_HOST'] ?? 'localhost';
    $dir = rtrim(str_replace('\\', '/', dirname($_SERVER['PHP_SELF'] ?? '/')), '/');
    return $scheme . '://' . $host . ($dir ? $dir : '');
}

function currencySymbol(string $currency): string
{
    return match ($currency) {
        'AED' => 'AED ',
        'EUR' => '€',
        'GBP' => '£',
        'EGP' => 'L.E ',
        default => '$',
    };
}

function normalizeSiteLanguage(string $language): string
{
    $language = strtolower(trim($language));
    return in_array($language, ['en', 'ar', 'both'], true) ? $language : 'en';
}

function siteLanguageDirection(string $language): string
{
    return normalizeSiteLanguage($language) === 'ar' ? 'rtl' : 'ltr';
}


function esc($value): string
{
    return installerEsc($value);
}

function siteLanguage(): string
{
    $language = $_SESSION['installer_shop']['site_language'] ?? ($_SESSION['installer_site_language'] ?? 'en');
    return normalizeSiteLanguage((string)$language);
}

function siteDirection(): string
{
    return siteLanguageDirection(siteLanguage());
}


