function normalizeBusinessType(string $type): string
{
    $profiles = businessProfiles();
    return isset($profiles[$type]) ? $type : 'automotive';
}

function installerBusinessProfile(?string $type = null): array
{
    $profiles = businessProfiles();
    $candidate = $type ?? (string)($_SESSION['installer_business_type'] ?? 'automotive');
    $candidate = normalizeBusinessType($candidate);
    return $profiles[$candidate] ?? $profiles['automotive'];
}

