function recommendedInstallerBundle(string $businessType): string
{
    return match (normalizeBusinessType($businessType)) {
        'electronics' => 'electronics_retail',
        'food' => 'food_industry',
        'general_trading' => 'general_trading',
        default => 'automotive_workshop',
    };
}

function normalizeInstallerBundle(string $bundleKey, ?string $businessType = null): string
{
    $bundles = installerBundleCatalog($businessType);
    return isset($bundles[$bundleKey]) ? $bundleKey : recommendedInstallerBundle($businessType ?? 'automotive');
}

function installerModulePlanFromSelection(string $businessType, string $bundleKey, array $selectedModules = []): array
{
    $catalog = installerModuleCatalog();
    $bundleKey = normalizeInstallerBundle($bundleKey, $businessType);
    $bundles = installerBundleCatalog($businessType);
    $bundle = $bundles[$bundleKey];
    $modules = $bundleKey === 'custom' ? $selectedModules : ($bundle['modules'] ?? []);
    $modules = array_values(array_unique(array_filter($modules, fn($m) => isset($catalog[$m]))));
    if (!$modules) {
        $fallback = recommendedInstallerBundle($businessType);
        $bundleKey = $fallback;
        $bundle = $bundles[$fallback];
        $modules = $bundle['modules'];
    }
    $priorities = [];
    foreach ($modules as $moduleCode) {
        $priorities[] = $catalog[$moduleCode]['priority'];
    }
    return [
        'business_type'=>$businessType,
        'bundle_key'=>$bundleKey,
        'bundle_label'=>$bundle['label'],
        'bundle_tag'=>$bundle['tag'] ?? '',
        'modules'=>$modules,
        'priorities'=>array_values(array_unique($priorities)),
        'catalog'=>$catalog,
    ];
}

function installerCurrentModulePlan(): array
{
    $businessType = normalizeBusinessType((string)($_SESSION['installer_business_type'] ?? 'automotive'));
    $bundleKey = normalizeInstallerBundle((string)($_SESSION['installer_module_bundle'] ?? recommendedInstallerBundle($businessType)), $businessType);
    $modules = $_SESSION['installer_enabled_modules'] ?? [];
    return installerModulePlanFromSelection($businessType, $bundleKey, is_array($modules) ? $modules : []);
}


if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    if ($currentStep === 'welcome') {
        $businessType = normalizeBusinessType(cleanInput('business_type', 'automotive'));
        $bundleKey = normalizeInstallerBundle(cleanInput('module_bundle', recommendedInstallerBundle($businessType)), $businessType);
        $postedModules = $_POST['enabled_modules'] ?? [];
        if (!is_array($postedModules)) {
            $postedModules = [];
        }
        $postedModules = array_map('strval', $postedModules);
        $modulePlan = installerModulePlanFromSelection($businessType, $bundleKey, $postedModules);
        $_SESSION['installer_business_type'] = $businessType;
        $_SESSION['installer_module_bundle'] = $modulePlan['bundle_key'];
        $_SESSION['installer_enabled_modules'] = $modulePlan['modules'];
        $_SESSION['installer_enabled_priorities'] = $modulePlan['priorities'];
        header('Location: ?step=database');
        exit;
    }

    if ($currentStep === 'database') {
        $db = [
            'host' => cleanInput('db_host', 'localhost'),
            'port' => cleanInput('db_port', '3306'),
            'name' => cleanInput('db_name', 'ecommerce_erp'),
            'user' => cleanInput('db_user'),
            'pass' => (string)($_POST['db_pass'] ?? ''),
            'prefix' => cleanInput('db_prefix', 'ec_') ?: 'ec_',
        ];
        try {
            new PDO('mysql:host=' . $db['host'] . ';port=' . $db['port'] . ';charset=utf8mb4', $db['user'], $db['pass'], [PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION]);
            $_SESSION['installer_db'] = $db;
            header('Location: ?step=account');
            exit;
        } catch (Throwable $e) {
            $error = 'Database connection failed: ' . $e->getMessage();
        }
    }

    if ($currentStep === 'account') {
        $password = (string)($_POST['admin_password'] ?? '');
        if ($password !== (string)($_POST['admin_password_confirm'] ?? '')) {
            $error = 'Admin passwords do not match.';
        } elseif (strlen($password) < 8) {
            $error = 'Admin password must be at least 8 characters.';
        } elseif (!filter_var(cleanInput('admin_email'), FILTER_VALIDATE_EMAIL)) {
            $error = 'Enter a valid admin email address.';
        } else {
            $currency = cleanInput('currency', 'AED');
            $language = normalizeSiteLanguage(cleanInput('site_language', 'en'));
            $_SESSION['installer_admin'] = [
                'email' => cleanInput('admin_email'),
                'password' => password_hash($password, PASSWORD_DEFAULT),
                'first_name' => cleanInput('first_name', 'Admin'),
                'last_name' => cleanInput('last_name', 'User'),
            ];
            $_SESSION['installer_shop'] = [
                'name' => cleanInput('shop_name', 'E-commerce'),
                'email' => cleanInput('shop_email', cleanInput('admin_email')),
                'phone' => cleanInput('shop_phone'),
                'address' => cleanInput('shop_address'),
                'currency' => $currency,
                'currency_symbol' => currencySymbol($currency),
                'site_language' => $language,
                'site_direction' => siteLanguageDirection($language),
                'timezone' => cleanInput('timezone', 'Asia/Dubai'),
                'url' => detectedBaseUrl(),
                'business_type' => normalizeBusinessType((string)($_SESSION['installer_business_type'] ?? 'automotive')),
                'module_bundle' => (string)($_SESSION['installer_module_bundle'] ?? recommendedInstallerBundle((string)($_SESSION['installer_business_type'] ?? 'automotive'))),
                'enabled_modules' => $_SESSION['installer_enabled_modules'] ?? [],
                'enabled_priorities' => $_SESSION['installer_enabled_priorities'] ?? [],
                'db_encryption_enabled' => cleanInput('db_encryption_enabled','1') === '1' ? '1' : '0',
                'app_encryption_key' => trim((string)($_POST['app_encryption_key'] ?? '')) !== '' ? trim((string)$_POST['app_encryption_key']) : base64_encode(random_bytes(32)),
            ];
            header('Location: ?step=install');
            exit;
        }
    }
}

if ($currentStep === 'install' && empty($_SESSION['installer_done'])) {
    try {
        if (empty($_SESSION['installer_db']) || empty($_SESSION['installer_admin']) || empty($_SESSION['installer_shop'])) {
            throw new RuntimeException('Installer session data is missing. Start again.');
        }
        $profile = installerBusinessProfile((string)($_SESSION['installer_business_type'] ?? ($_SESSION['installer_shop']['business_type'] ?? 'automotive')));
        $modulePlan = installerCurrentModulePlan();
        runInstallation($_SESSION['installer_db'], $_SESSION['installer_admin'], $_SESSION['installer_shop'], $profile, $modulePlan);
        $_SESSION['installer_done'] = true;
        header('Location: ?step=finish');
        exit;
    } catch (Throwable $e) {
        $error = $e->getMessage();
    }
}

function runInstallation(array $db, array $admin, array $shop, array $profile, array $modulePlan = []): void
{
    $pdo = new PDO('mysql:host=' . $db['host'] . ';port=' . $db['port'] . ';charset=utf8mb4', $db['user'], $db['pass'], [
        PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    ]);

    $dbName = preg_replace('/[^a-zA-Z0-9_]/', '', $db['name']);
    if ($dbName === '') {
        throw new RuntimeException('Database name is invalid.');
    }
    $pdo->exec('CREATE DATABASE IF NOT EXISTS `' . $dbName . '` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci');
    $pdo->exec('USE `' . $dbName . '`');

    $prefix = preg_replace('/[^a-zA-Z0-9_]/', '', $db['prefix'] ?: 'ec_');
    if ($prefix === '') {
        $prefix = 'ec_';
    }
    $db['name'] = $dbName;
    $db['prefix'] = $prefix;

    createDatabase($pdo, $prefix);
    seedDatabase($pdo, $prefix, $admin, $shop, $profile, $modulePlan);
    createDirectories();
                installerEnsureLicenseDatabase($pdo, $db['prefix']);
writeGeneratedFiles($db, $shop, $profile);
}

