    $sql[] = 'CREATE TABLE `' . $prefix . 'cron_runs` (id INT AUTO_INCREMENT PRIMARY KEY,run_key VARCHAR(120),started_at DATETIME NULL,finished_at DATETIME NULL,status VARCHAR(40) DEFAULT "running",summary TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'dashboard_widget_preferences` (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,role_slug VARCHAR(160) NULL,widget_key VARCHAR(160) NOT NULL,title VARCHAR(255),sort_order INT DEFAULT 0,is_enabled TINYINT(1) DEFAULT 1,config_json LONGTEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_widget_pref (user_id,role_slug,widget_key)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'deployment_checklist_items` (id INT AUTO_INCREMENT PRIMARY KEY,item_key VARCHAR(160) NOT NULL UNIQUE,title VARCHAR(255) NOT NULL,category VARCHAR(120),severity VARCHAR(40) DEFAULT "medium",status VARCHAR(40) DEFAULT "open",recommendation TEXT,completed_by INT NULL,completed_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'subscription_plans` (id INT AUTO_INCREMENT PRIMARY KEY,plan_code VARCHAR(120) NOT NULL UNIQUE,plan_name VARCHAR(255) NOT NULL,billing_cycle VARCHAR(40) DEFAULT "monthly",monthly_price DECIMAL(12,2) DEFAULT 0,yearly_price DECIMAL(12,2) DEFAULT 0,user_limit INT DEFAULT 5,branch_limit INT DEFAULT 1,warehouse_limit INT DEFAULT 1,product_limit INT DEFAULT 1000,storage_limit_mb INT DEFAULT 1024,api_call_limit_monthly INT DEFAULT 10000,status VARCHAR(40) DEFAULT "active",description TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'plan_features` (id INT AUTO_INCREMENT PRIMARY KEY,subscription_plan_id INT NOT NULL,feature_key VARCHAR(160) NOT NULL,feature_name VARCHAR(255),is_enabled TINYINT(1) DEFAULT 1,limit_value VARCHAR(120),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_plan_feature (subscription_plan_id,feature_key)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'tenant_subscriptions` (id INT AUTO_INCREMENT PRIMARY KEY,company_id INT NOT NULL,subscription_plan_id INT NULL,subscription_number VARCHAR(120) NOT NULL UNIQUE,status VARCHAR(40) DEFAULT "trial",start_date DATE,end_date DATE,next_billing_date DATE NULL,billing_cycle VARCHAR(40) DEFAULT "monthly",amount DECIMAL(12,2) DEFAULT 0,auto_renew TINYINT(1) DEFAULT 1,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'tenant_usage_snapshots` (id INT AUTO_INCREMENT PRIMARY KEY,company_id INT NOT NULL,snapshot_date DATE NOT NULL,user_count INT DEFAULT 0,branch_count INT DEFAULT 0,warehouse_count INT DEFAULT 0,product_count INT DEFAULT 0,storage_used_mb DECIMAL(12,2) DEFAULT 0,api_calls_month INT DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_tenant_usage_date (company_id,snapshot_date)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'license_keys` (id INT AUTO_INCREMENT PRIMARY KEY,license_key_hash VARCHAR(255) NOT NULL UNIQUE,license_prefix VARCHAR(40),license_name VARCHAR(255),company_id INT NULL,subscription_plan_id INT NULL,status VARCHAR(40) DEFAULT "active",issued_to VARCHAR(255),issued_email VARCHAR(255),domain_name VARCHAR(255),max_users INT DEFAULT 0,max_branches INT DEFAULT 0,modules_json LONGTEXT,issued_at DATETIME NULL,expires_at DATETIME NULL,last_validated_at DATETIME NULL,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'module_entitlements` (id INT AUTO_INCREMENT PRIMARY KEY,company_id INT NULL,license_key_id INT NULL,module_key VARCHAR(160) NOT NULL,module_name VARCHAR(255),is_enabled TINYINT(1) DEFAULT 1,limit_value VARCHAR(120),source VARCHAR(80) DEFAULT "license",created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_module_company (company_id,module_key)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'license_validation_logs` (id INT AUTO_INCREMENT PRIMARY KEY,license_key_id INT NULL,status VARCHAR(40),domain_name VARCHAR(255),ip_address VARCHAR(80),message TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_module_catalog` (id INT AUTO_INCREMENT PRIMARY KEY,module_key VARCHAR(160) NOT NULL UNIQUE,module_name VARCHAR(255),module_group VARCHAR(120) DEFAULT "Core",description TEXT,default_enabled TINYINT(1) DEFAULT 1,status VARCHAR(40) DEFAULT "active",created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_plan_modules` (id INT AUTO_INCREMENT PRIMARY KEY,subscription_plan_id INT NOT NULL,module_key VARCHAR(160) NOT NULL,module_name VARCHAR(255),is_enabled TINYINT(1) DEFAULT 1,included_limit VARCHAR(120),overage_price DECIMAL(12,2) DEFAULT 0,status VARCHAR(40) DEFAULT "active",created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_saas_plan_module (subscription_plan_id,module_key)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_trial_accounts` (id INT AUTO_INCREMENT PRIMARY KEY,trial_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NULL,subscription_plan_id INT NULL,contact_name VARCHAR(255),contact_email VARCHAR(255),contact_phone VARCHAR(80),trial_start DATE NULL,trial_end DATE NULL,status VARCHAR(40) DEFAULT "active",converted_subscription_id INT NULL,notes TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_subscription_invoices` (id INT AUTO_INCREMENT PRIMARY KEY,invoice_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NOT NULL,tenant_subscription_id INT NULL,subscription_plan_id INT NULL,invoice_date DATE NULL,due_date DATE NULL,billing_period_start DATE NULL,billing_period_end DATE NULL,subtotal DECIMAL(14,2) DEFAULT 0,tax_amount DECIMAL(14,2) DEFAULT 0,total DECIMAL(14,2) DEFAULT 0,balance_due DECIMAL(14,2) DEFAULT 0,status VARCHAR(40) DEFAULT "unpaid",notes TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_subscription_payments` (id INT AUTO_INCREMENT PRIMARY KEY,payment_number VARCHAR(120) NOT NULL UNIQUE,saas_subscription_invoice_id INT NOT NULL,company_id INT NOT NULL,payment_date DATE NULL,amount DECIMAL(14,2) DEFAULT 0,payment_method VARCHAR(120),payment_reference VARCHAR(180),status VARCHAR(40) DEFAULT "received",notes TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_plan_change_requests` (id INT AUTO_INCREMENT PRIMARY KEY,request_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NOT NULL,current_plan_id INT NULL,requested_plan_id INT NULL,change_type VARCHAR(40) DEFAULT "upgrade",status VARCHAR(40) DEFAULT "pending",requested_by INT NULL,approved_by INT NULL,requested_at DATETIME NULL,approved_at DATETIME NULL,effective_date DATE NULL,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_usage_enforcement_logs` (id INT AUTO_INCREMENT PRIMARY KEY,enforcement_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NOT NULL,tenant_subscription_id INT NULL,module_key VARCHAR(160),metric_key VARCHAR(120),current_value DECIMAL(14,2) DEFAULT 0,limit_value DECIMAL(14,2) DEFAULT 0,severity VARCHAR(40) DEFAULT "warning",status VARCHAR(40) DEFAULT "open",message TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,resolved_at DATETIME NULL) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_tenant_domains` (id INT AUTO_INCREMENT PRIMARY KEY,domain_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NOT NULL,domain_name VARCHAR(255) NOT NULL,is_primary TINYINT(1) DEFAULT 0,status VARCHAR(40) DEFAULT "pending",verified_at DATETIME NULL,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_saas_domain (domain_name)) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'saas_onboarding_tasks` (id INT AUTO_INCREMENT PRIMARY KEY,task_number VARCHAR(120) NOT NULL UNIQUE,company_id INT NOT NULL,task_title VARCHAR(255),task_type VARCHAR(120) DEFAULT "setup",status VARCHAR(40) DEFAULT "pending",due_date DATE NULL,completed_at DATETIME NULL,assigned_to INT NULL,notes TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'update_channels` (id INT AUTO_INCREMENT PRIMARY KEY,channel_code VARCHAR(120) NOT NULL UNIQUE,channel_name VARCHAR(255),stability VARCHAR(40) DEFAULT "stable",status VARCHAR(40) DEFAULT "active",description TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'system_updates` (id INT AUTO_INCREMENT PRIMARY KEY,update_code VARCHAR(120) NOT NULL UNIQUE,channel_id INT NULL,version_label VARCHAR(120),release_title VARCHAR(255),release_notes LONGTEXT,package_url VARCHAR(255),checksum VARCHAR(255),status VARCHAR(40) DEFAULT "available",is_required TINYINT(1) DEFAULT 0,installed_by INT NULL,installed_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB';
    $sql[] = 'CREATE TABLE `' . $prefix . 'upgrade_mode_events` (id INT AUTO_INCREMENT PRIMARY KEY,event_type VARCHAR(120),status VARCHAR(40) DEFAULT "open",from_version VARCHAR(120),to_version VARCHAR(120),description TEXT,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,completed_at DATETIME NULL) ENGINE=InnoDB';
    foreach ($sql as $statement) {
        $pdo->exec($statement);
    }
}

