    $warehouseStockStmt = $pdo->prepare('INSERT INTO `' . $prefix . 'warehouse_stock` (product_id,company_id,branch_id,warehouse_id,location_id,quantity,reserved_quantity,reorder_level,average_unit_cost,stock_value) VALUES (?,?,?,?,?,?,0,?,?,?)');
