        $unitCost = round($price * $defaultCostRatio, 2);
        $sku = (string)($product[8] ?? ('SKU-' . $productId));
        $reorder = max(5, (int)ceil(max(1, $stock) * 0.15));
        $location = !empty($product[16]) ? 'Digital' : 'Main Store';
        $stockValue = round($stock * $unitCost, 2);
        $productCostStmt->execute([$unitCost,$unitCost,$productId]);
        $stmt->execute([$productId, $sku, $stock, $reorder, $location]);
        $warehouseStockStmt->execute([$productId,$defaultCompanyId,$defaultBranchId,$defaultWarehouseId,$defaultLocationId,$stock,$reorder,$unitCost,$stockValue]);
