function createDirectories(): void
{
    foreach ([__DIR__,] as $unused) {}
    $dirs = [__DIR__ . '/admin/assets/css',__DIR__ . '/admin/assets/js',__DIR__ . '/admin/erp',__DIR__ . '/employee',__DIR__ . '/user',__DIR__ . '/products',__DIR__ . '/downloads',__DIR__ . '/services',__DIR__ . '/blog',__DIR__ . '/includes',__DIR__ . '/uploads/products',__DIR__ . '/uploads/downloads',__DIR__ . '/uploads/homepage',__DIR__ . '/assets/css',__DIR__ . '/assets/js',__DIR__ . '/assets/images',__DIR__ . '/tools'];
    foreach ($dirs as $dir) {
        if (!is_dir($dir) && !mkdir($dir, 0775, true) && !is_dir($dir)) {
            throw new RuntimeException('Unable to create directory: ' . $dir);
        }
    }
}


function installerEnsureLicenseDatabase(PDO $pdo, string $prefix): void
{
    $pdo->exec('CREATE TABLE IF NOT EXISTS `' . $prefix . 'license_settings` (setting_key VARCHAR(190) PRIMARY KEY,setting_value LONGTEXT NULL,updated_at TIMESTAMP NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci');

    $defaults = [
        'license_status' => 'trial',
        'license_enforcement_mode' => 'enforce',
        'license_trial_product_limit' => '10',
        'license_trial_category_limit' => '10',
        'license_trial_customer_limit' => '10',
        'license_trial_order_limit' => '10',
        'license_trial_user_limit' => '10',
        'license_trial_branch_limit' => '1',
        'license_trial_warehouse_limit' => '1',
        'license_trial_invoice_limit' => '10',
        'license_limits' => json_encode([
            'products' => 5,
            'categories' => 5,
            'customers' => 5,
            'orders' => 5,
            'users' => 3,
            'branches' => 1,
            'warehouses' => 1,
            'invoices' => 10,
        ], JSON_UNESCAPED_SLASHES),
        'license_modules' => json_encode(['products','categories','customers','orders','inventory_basic'], JSON_UNESCAPED_SLASHES),
        'license_plan' => 'trial',
    ];

    $stmt = $pdo->prepare('INSERT INTO `' . $prefix . 'license_settings` (setting_key,setting_value,updated_at) VALUES (?,?,NOW()) ON DUPLICATE KEY UPDATE setting_value=setting_value,updated_at=updated_at');
    foreach ($defaults as $key => $value) {
        $stmt->execute([$key, (string)$value]);
    }

    // Force enforce mode because monitor mode only displays warnings and does not block creation.
    $stmt = $pdo->prepare('INSERT INTO `' . $prefix . 'license_settings` (setting_key,setting_value,updated_at) VALUES ("license_enforcement_mode","enforce",NOW()) ON DUPLICATE KEY UPDATE setting_value="enforce",updated_at=NOW()');
    $stmt->execute();

    try {
        $stmt = $pdo->prepare('INSERT INTO `' . $prefix . 'settings` (key_name,value) VALUES (?,?) ON DUPLICATE KEY UPDATE value=VALUES(value)');
        foreach ($defaults as $key => $value) {
            $stmt->execute([$key, (string)$value]);
        }
        $stmt->execute(['license_enforcement_mode', 'enforce']);
    } catch (Throwable $ignored) {
        // Some repair contexts may not have the normal settings table yet.
    }
}


function writeGeneratedFiles(array $db, array $shop, array $profile): void
{
    $replacements = [
        '{{DB_HOST}}' => addslashes($db['host']), '{{DB_PORT}}' => addslashes($db['port']), '{{DB_NAME}}' => addslashes($db['name']), '{{DB_USER}}' => addslashes($db['user']), '{{DB_PASS}}' => addslashes($db['pass']), '{{DB_PREFIX}}' => addslashes($db['prefix']),
        '{{SHOP_NAME}}' => addslashes($shop['name']), '{{SHOP_EMAIL}}' => addslashes($shop['email']), '{{SHOP_PHONE}}' => addslashes($shop['phone']), '{{SHOP_ADDRESS}}' => addslashes($shop['address']), '{{CURRENCY}}' => addslashes($shop['currency']), '{{CURRENCY_SYMBOL}}' => addslashes($shop['currency_symbol']), '{{SITE_LANGUAGE}}' => addslashes($shop['site_language'] ?? 'en'), '{{SITE_DIRECTION}}' => addslashes($shop['site_direction'] ?? 'ltr'), '{{SHOP_URL}}' => addslashes($shop['url']), '{{TIMEZONE}}' => addslashes($shop['timezone']),
        '{{BUSINESS_TYPE}}' => addslashes($profile['code'] ?? 'automotive'), '{{BUSINESS_LABEL}}' => addslashes($profile['label'] ?? 'Automotive ERP & E-commerce'),
        '{{APP_ENCRYPTION_KEY}}' => addslashes($shop['app_encryption_key'] ?? base64_encode(random_bytes(32))),
        '{{DATABASE_ENCRYPTION_TOOLS_ENABLED}}' => addslashes($shop['db_encryption_enabled'] ?? '1'),
        '{{LICENSE_PUBLIC_KEY_B64}}' => '',
        '{{LICENSE_PRIVATE_KEY_B64}}' => '',
    ];
    foreach (generatedFileTemplates() as $relativePath => $template) {
        $absolutePath = __DIR__ . '/' . $relativePath;
        $dir = dirname($absolutePath);
        if (!is_dir($dir) && !mkdir($dir, 0775, true) && !is_dir($dir)) {
            throw new RuntimeException('Unable to create file directory: ' . $dir);
        }
        $content = strtr($template, $replacements);
        if (file_put_contents($absolutePath, $content) === false) {
            throw new RuntimeException('Unable to write file: ' . $relativePath);
        }
    }
}

