$b2cParams=$countParams;$b2cWhere=$countWhere!==''?$countWhere.' AND c.customer_type="b2c"':' WHERE c.customer_type="b2c"';$b2cStmt=$pdo->prepare('SELECT COUNT(*) FROM '.table('customers').' c'.$b2cWhere);$b2cStmt->execute($b2cParams);
