$stmt=$pdo->prepare('SELECT id,payment_number doc_number,amount,DATE(COALESCE(paid_at,created_at)) doc_date,status FROM ' . table('payments') . ' WHERE customer_id=? AND status="received"');$stmt->execute([$id]);foreach($stmt->fetchAll() as $row){$entries[]=['date'=>$row['doc_date'],'type'=>'Payment','doc'=>$row['doc_number'],'debit'=>0,'credit'=>(float)$row['amount'],'link'=>ADMIN_URL.'/erp/finance.php','status'=>$row['status']];}
$stmt=$pdo->prepare('SELECT id,credit_note_number doc_number,total,issue_date doc_date,status FROM ' . table('credit_notes') . ' WHERE customer_id=? AND status="approved"');$stmt->execute([$id]);foreach($stmt->fetchAll() as $row){$entries[]=['date'=>$row['doc_date'],'type'=>'Credit Note','doc'=>$row['doc_number'],'debit'=>0,'credit'=>(float)$row['total'],'link'=>ADMIN_URL.'/erp/view-credit-note.php?id='.(int)$row['id'],'status'=>$row['status']];}
usort($entries,fn($a,$b)=>strcmp((string)$a['date'].'-'.$a['type'],(string)$b['date'].'-'.$b['type']));
$running=0;$debits=0;$credits=0;foreach($entries as &$entry){$debits+=$entry['debit'];$credits+=$entry['credit'];$running+=$entry['debit']-$entry['credit'];$entry['balance']=$running;}unset($entry);
