$condition=selectedScopeCondition('s',$params,$filters,['company_id','branch_id']);$condition.=scopeQueryCondition($pdo,'s',$params,false);
if($where===''){$where=$condition!==''?' WHERE '.substr($condition,5):'';}else{$where.=$condition;}
