    $stmt=$pdo->prepare('SELECT * FROM ' . table('debit_notes') . ' WHERE id=? LIMIT 1 FOR UPDATE');$stmt->execute([$id]);$note=$stmt->fetch();
    if(!$note || $note['status']!=='draft'){throw new RuntimeException('Only draft debit notes can be approved.');}
