-6"><input class="form-control" type="number" step="0.01" name="credit" placeholder="Credit"></div></div><button class="btn btn-outline-primary w-100 mt-3">Add Line</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Reconciliation Runs</h2><table class="table align-middle"><thead><tr><th>Recon</th><th>Range</th><th>Statement</th><th>Book</th><th>Variance</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($recons as $r): ?><tr><td><strong><?php echo esc($r['reconciliation_number']); ?></strong></td><td><?php echo esc($r['date_from'].' → '.$r['date_to']); ?></td><td><?php echo money($r['statement_ending_balance']); ?></td><td><?php echo money($r['book_ending_balance']); ?></td><td class="<?php echo abs((float)$r['variance'])>0.01?'money-negative':'money-positive'; ?>"><?php echo money($r['variance']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td><td><?php if($r['status']!=='reconciled'): ?><form method="post"><input type="hidden" name="action" value="mark_reconciled"><input type="hidden" name="id" value="<?php echo (int)$r['id']; ?>"><button class="btn btn-sm btn-outline-success">Finalize</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$recons): ?><tr><td colspan="7" class="text-secondary">No reconciliations yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Statement Lines</h2><table class="table align-middle"><thead><tr><th>Date</th><th>Description</th><th>Debit</th><th>Credit</th><th>Status</th><th>Match</th></tr></thead><tbody><?php foreach($lines as $line): ?><tr><td><?php echo esc($line['statement_date']); ?></td><td><strong><?php echo esc($line['description']); ?></strong><div class="small text-secondary"><?php echo esc($line['reference']); ?></div></td><td><?php echo money($line['debit']); ?></td><td><?php echo money($line['credit']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($line['status'])); ?>"><?php echo esc($line['status']); ?></span></td><td><?php if($line['status']!=='matched'): ?><form method="post" class="d-flex gap-1"><input type="hidden" name="action" value="match_line"><input type="hidden" name="statement_id" value="<?php echo (int)$line['id']; ?>"><select class="form-select form-select-sm" name="journal_line_id"><?php foreach($journalLines as $jl): ?><option value="<?php echo (int)$jl['id']; ?>"><?php echo esc($jl['journal_number'].' · '.$jl['entry_date'].' · '.money((float)$jl['debit']-(float)$jl['credit'])); ?></option><?php endforeach; ?></select><button class="btn btn-sm btn-outline-primary">Match</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$lines): ?><tr><td colspan="6" class="text-secondary">No statement lines.</td></tr><?php endif; ?></tbody></table></div></div></div>
