  $stmt->execute([$companyId,$branchId,$code,$name,trim((string)($_POST['address']??'')),trim((string)($_POST['status']??'active')),!empty($_POST['is_default'])?1:0]);
  $id=(int)$pdo->lastInsertId();if(!empty($_POST['is_default'])){$pdo->prepare('UPDATE '.table('warehouses').' SET is_default=CASE WHEN id=? THEN 1 ELSE 0 END WHERE branch_id=?')->execute([$id,$branchId]);}
