  $stmt->execute([$warehouseId,$code,$name,trim((string)($_POST['zone_type']??'general')),trim((string)($_POST['status']??'active'))]);
  logActivity($pdo,'Organization','warehouse_location_created','Warehouse location '.$code.' created.','warehouse_location',(int)$pdo->lastInsertId());flash('success','Warehouse location created.');redirect(ADMIN_URL.'/erp/warehouses.php');
}
$warehouses=$pdo->query('SELECT w.*,c.company_code,c.company_name,b.branch_code,b.branch_name,(SELECT COUNT(*) FROM '.table('warehouse_locations').' l WHERE l.warehouse_id=w.id) location_count,(SELECT COALESCE(SUM(quantity),0) FROM '.table('warehouse_stock').' ws WHERE ws.warehouse_id=w.id) stock_units FROM '.table('warehouses').' w LEFT JOIN '.table('companies').' c ON c.id=w.company_id LEFT JOIN '.table('branches').' b ON b.id=w.branch_id ORDER BY c.company_name,b.branch_name,w.is_default DESC,w.warehouse_name')->fetchAll();
$locations=$pdo->query('SELECT l.*,w.warehouse_code,w.warehouse_name FROM '.table('warehouse_locations').' l LEFT JOIN '.table('warehouses').' w ON w.id=l.warehouse_id ORDER BY w.warehouse_name,l.location_code')->fetchAll();
include dirname(__DIR__).'/header.php';
$warehouseLimitReached = function_exists('licenseTrialLimitReached') ? licenseTrialLimitReached('warehouses', $pdo) : false;
$warehouseLimit = function_exists('licensePlanLimit') ? licensePlanLimit('warehouses') : null;
$warehouseCount = function_exists('currentLicenseEntityCount') ? currentLicenseEntityCount('warehouses', $pdo) : count($warehouses);
?>
