if($_SERVER['REQUEST_METHOD']==='POST'){
  $userId=(int)($_POST['user_id']??0);$companyId=(int)($_POST['company_id']??0);$branchId=(int)($_POST['branch_id']??0);$warehouseId=(int)($_POST['warehouse_id']??0);
  if($userId<=0){flash('error','Select a user.');redirect(ADMIN_URL.'/erp/user-branch-access.php');}
  if(!empty($_POST['is_default'])){$pdo->prepare('UPDATE '.table('user_branch_access').' SET is_default=0 WHERE user_id=?')->execute([$userId]);$pdo->prepare('UPDATE '.table('users').' SET default_company_id=?,default_branch_id=?,default_warehouse_id=? WHERE id=?')->execute([$companyId?:null,$branchId?:null,$warehouseId?:null,$userId]);}
  $stmt=$pdo->prepare('INSERT INTO '.table('user_branch_access').' (user_id,company_id,branch_id,warehouse_id,can_view,can_transact,is_default) VALUES (?,?,?,?,?,?,?)');
  $stmt->execute([$userId,$companyId?:null,$branchId?:null,$warehouseId?:null,!empty($_POST['can_view'])?1:0,!empty($_POST['can_transact'])?1:0,!empty($_POST['is_default'])?1:0]);
  logActivity($pdo,'Organization','user_branch_access_added','Branch access assigned to user #'.$userId.'.','user',$userId);flash('success','User branch access created.');redirect(ADMIN_URL.'/erp/user-branch-access.php');
}
if(isset($_GET['delete'])){$pdo->prepare('DELETE FROM '.table('user_branch_access').' WHERE id=?')->execute([(int)$_GET['delete']]);flash('success','Access row removed.');redirect(ADMIN_URL.'/erp/user-branch-access.php');}
$rows=$pdo->query('SELECT uba.*,u.email,u.first_name,u.last_name,c.company_code,c.company_name,b.branch_code,b.branch_name,w.warehouse_code,w.warehouse_name FROM '.table('user_branch_access').' uba LEFT JOIN '.table('users').' u ON u.id=uba.user_id LEFT JOIN '.table('companies').' c ON c.id=uba.company_id LEFT JOIN '.table('branches').' b ON b.id=uba.branch_id LEFT JOIN '.table('warehouses').' w ON w.id=uba.warehouse_id ORDER BY u.email,uba.is_default DESC')->fetchAll();
include dirname(__DIR__).'/header.php';
