$stmt=$pdo->prepare('SELECT so.*,c.customer_code,i.invoice_number,dn.delivery_number FROM '.table('sales_orders').' so LEFT JOIN '.table('customers').' c ON c.id=so.customer_id LEFT JOIN '.table('invoices').' i ON i.id=so.converted_invoice_id LEFT JOIN '.table('delivery_notes').' dn ON dn.id=so.delivery_note_id'.$where.' ORDER BY so.created_at DESC,so.id DESC LIMIT 250');
$stmt->execute($params);$rows=$stmt->fetchAll();
$summary=['draft'=>0,'pending_approval'=>0,'approved'=>0,'converted'=>0,'blocked'=>0,'value'=>0.0];
foreach($rows as $row){$statusKey=(string)($row['status']??'');if(isset($summary[$statusKey])){$summary[$statusKey]++;}$summary['value']+=(float)$row['total'];if(($row['credit_check_status']??'')==='blocked'){$summary['blocked']++;}}
include dirname(__DIR__).'/header.php';
