<?php
$pageTitle='Delivery Notes';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('delivery_notes');
$pdo=getDB();
$scopeOptions=scopeSelectOptions($pdo);
$filters=requestScopeFilters();
$status=trim((string)($_GET['status']??''));

$params=[];$where='';
if($status!==''){$where=' WHERE dn.status=?';$params[]=$status;}
$condition=selectedScopeCondition('dn',$params,$filters,['company_id','branch_id','warehouse_id']);$condition.=scopeQueryCondition($pdo,'dn',$params,false);
if($where===''){$where=$condition!==''?' WHERE '.substr($condition,5):'';}else{$where.=$condition;}
$stmt=$pdo->prepare('SELECT dn.*,so.sales_order_number,i.invoice_number,u1.email dispatched_email,u2.email delivered_email FROM '.table('delivery_notes').' dn LEFT JOIN '.table('sales_orders').' so ON so.id=dn.sales_order_id LEFT JOIN '.table('invoices').' i ON i.id=dn.invoice_id LEFT JOIN '.table('users').' u1 ON u1.id=dn.dispatched_by LEFT JOIN '.table('users').' u2 ON u2.id=dn.delivered_by'.$where.' ORDER BY dn.created_at DESC,dn.id DESC LIMIT 250');
$stmt->execute($params);$rows=$stmt->fetchAll();
$summary=['draft'=>0,'dispatched'=>0,'delivered'=>0,'cancelled'=>0];foreach($rows as $row){$k=(string)($row['status']??'');if(isset($summary[$k])){$summary[$k]++;}}
include dirname(__DIR__).'/header.php';
?>
