<?php
$pageTitle='Job Cards / Workshop Orders';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('job_cards');
$pdo=getDB();
$scopeOptions=scopeSelectOptions($pdo);
$filters=requestScopeFilters();
$status=trim((string)($_GET['status']??''));
$params=[];$where='';
if($status!==''){$where=' WHERE jc.status=?';$params[]=$status;}
$condition=selectedScopeCondition('jc',$params,$filters,['company_id','branch_id','warehouse_id']);$condition.=scopeQueryCondition($pdo,'jc',$params,false);
if($where===''){$where=$condition!==''?' WHERE '.substr($condition,5):'';}else{$where.=$condition;}
$stmt=$pdo->prepare('SELECT jc.*,c.customer_code,u.email technician_email,i.invoice_number FROM '.table('job_cards').' jc LEFT JOIN '.table('customers').' c ON c.id=jc.customer_id LEFT JOIN '.table('users').' u ON u.id=jc.technician_user_id LEFT JOIN '.table('invoices').' i ON i.id=jc.invoice_id'.$where.' ORDER BY jc.created_at DESC,jc.id DESC LIMIT 250');
$stmt->execute($params);$rows=$stmt->fetchAll();
$summary=['draft'=>0,'diagnosis'=>0,'in_progress'=>0,'completed'=>0,'invoiced'=>0,'value'=>0.0,'cost'=>0.0];foreach($rows as $row){$k=(string)$row['status'];if(isset($summary[$k])){$summary[$k]++;}$summary['value']+=(float)$row['estimated_total'];$summary['cost']+=(float)$row['actual_cost'];}
include dirname(__DIR__).'/header.php';
