d><td><?php echo number_format((float)$row['quantity_used'],2); ?></td><td><?php echo money($row['unit_price']); ?></td><td><?php echo money($row['unit_cost']); ?></td><td><?php echo money($row['line_total']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($row['status'])); ?>"><?php echo esc($row['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-xl-4"><div class="card-admin p-4 mb-4"><div class="erp-kicker">Workflow</div><div class="d-grid gap-2 mt-3"><?php if(in_array($job['status'],['draft','diagnosis','waiting_parts'],true)): ?><form method="post"><button class="btn btn-warning w-100" name="action" value="start">Start Job</button></form><?php endif; ?><?php if(in_array($job['status'],['draft','diagnosis','in_progress','waiting_parts'],true)): ?><form method="post"><button class="btn btn-success w-100" name="action" value="complete">Complete & Issue Parts</button></form><?php endif; ?><?php if($job['status']==='completed'): ?><form method="post"><button class="btn btn-brand w-100" name="action" value="invoice">Create Invoice</button></form><?php endif; ?><?php if(!in_array($job['status'],['invoiced','cancelled'],true)): ?><form method="post"><button class="btn btn-outline-danger w-100" name="action" value="cancel">Cancel</button></form><?php endif; ?></div></div><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="add_labor"><div class="erp-kicker">Add Labor</div><input class="form-control mb-2" name="task_name" placeholder="Task name"><textarea class="form-control mb-2" name="description" rows="2" placeholder="Description"></textarea><select class="form-select mb-2" name="technician_user_id"><option value="0">Technician</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="h