    $stmt=$pdo->prepare('INSERT INTO '.table('service_contracts').' (company_id,branch_id,cost_center_id,contract_number,customer_id,customer_name,contract_type,start_date,end_date,contract_value,billing_frequency,next_billing_date,visits_included,response_sla_hours,status,notes) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,"active",?)');
    $stmt->execute([(int)$scope['company_id']?:null,(int)$scope['branch_id']?:null,(int)($_POST['cost_center_id']??0)?:null,$number,$customerId,$customerName,trim((string)($_POST['contract_type']??'AMC')),trim((string)($_POST['start_date']??date('Y-m-d'))),trim((string)($_POST['end_date']??''))?:null,max(0,(float)($_POST['contract_value']??0)),trim((string)($_POST['billing_frequency']??'monthly')),trim((string)($_POST['next_billing_date']??''))?:null,max(0,(int)($_POST['visits_included']??0)),max(1,(int)($_POST['response_sla_hours']??24)),trim((string)($_POST['notes']??''))]);
    logActivity($pdo,'Contracts','service_contract_created','Service contract '.$number.' created.','service_contract',(int)$pdo->lastInsertId());
    flash('success','Service contract created.');
