<?php
$pageTitle='Create Project';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('projects');
$pdo=getDB();$scope=operationalScope($pdo);$scopeOptions=scopeSelectOptions($pdo);
$customers=$pdo->query('SELECT id,customer_code,company_name,contact_name FROM '.table('customers').' WHERE status="active" ORDER BY company_name,contact_name LIMIT 400')->fetchAll();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" AND (can_login_erp=1 OR role="admin") ORDER BY first_name,email LIMIT 300')->fetchAll();
$costCenters=$pdo->query('SELECT id,cost_center_code,cost_center_name FROM '.table('cost_centers').' WHERE status="active" ORDER BY cost_center_code')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $pdo->beginTransaction();
  try{
    $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)setting('default_warehouse_id','0'),'location_id'=>(int)setting('default_location_id','0')];
    enforceScopeAllowed($pdo,$scope['company_id'],$scope['branch_id'],0,true);
    $number=nextScopedDocumentNumber($pdo,'project','PRJ',$scope);
    $customerId=(int)($_POST['customer_id']??0)?:null;$customerName=trim((string)($_POST['customer_name']??''));
    if($customerId){$s=$pdo->prepare('SELECT company_name,contact_name FROM '.table('customers').' WHERE id=?');$s->execute([$customerId]);$c=$s->fetch();if($c){$customerName=trim(($c['company_name']?:'').' '.($c['contact_name']?:''));}}
    $budget=max(0,(float)($_POST['budget_amount']??0));$revenue=max(0,(float)($_POST['revenue_amount']??0));
    $stmt=$pdo->prepare('INSERT INTO '.table('projects').' (company_id,branch_id,cost_center_id,project_number,project_name,customer_id,customer_name,project_manager_user_id,start_date,end_date,budget_amount,revenue_amount,cost_amount,margin_amount,status,description) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,0,?,"planning",?)');
    $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,(int)($_POST['cost_center_id']??0)?:null,$number,trim((string)($_POST['project_name']??'')),$customerId,$customerName,(int)($_POST['project_manager_user_id']??0)?:null,trim((string)($_POST['start_date']??''))?:null,trim((string)($_POST['end_date']??''))?:null,$budget,$revenue,round($revenue,2),trim((string)($_POST['description']??''))]);
    $id=(int)$pdo->lastInsertId();projectRecalculate($pdo,$id);logActivity($pdo,'Projects','project_created','Project '.$number.' created.','project',$id);
    $pdo->commit();flash('success','Project created.');redirect(ADMIN_URL.'/erp/view-project.php?id='.$id);
  }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());redirect(ADMIN_URL.'/erp/create-project.php');}
}
include dirname(__DIR__).'/header.php';
?>
