  $pdo->prepare('UPDATE '.table('notifications').' SET is_read=1,read_at=NOW() WHERE id=?')->execute([$id]);
  redirect(ADMIN_URL.'/erp/notifications.php');
}
if(isset($_GET['mark_all'])){
