      $email=trim((string)$_POST['email']);$password=(string)($_POST['password']??'');
      if(!filter_var($email,FILTER_VALIDATE_EMAIL)||strlen($password)<8){throw new RuntimeException('Valid email and 8+ character password are required.');}
      $stmt=$pdo->prepare('INSERT INTO '.table('users').' (email,password,first_name,last_name,role,can_login_erp,status) VALUES (?,?,?,?, "vendor",0,"active")');
      $stmt->execute([$email,password_hash($password,PASSWORD_DEFAULT),trim((string)$_POST['first_name']),trim((string)$_POST['last_name'])]);
      $userId=(int)$pdo->lastInsertId();
      $pdo->prepare('INSERT INTO '.table('supplier_user_access').' (supplier_id,user_id,role_label,can_view_pos,can_view_invoices,can_upload_documents,status) VALUES (?,?,?,?,?,?, "active")')->execute([(int)$_POST['supplier_id'],$userId,trim((string)($_POST['role_label']??'Vendor User')),1,1,1]);
      flash('success','Vendor user created and assigned.');
    }else{
      $pdo->prepare('INSERT INTO '.table('supplier_user_access').' (supplier_id,user_id,role_label,can_view_pos,can_view_invoices,can_upload_documents,status) VALUES (?,?,?,?,?,?, "active") ON DUPLICATE KEY UPDATE role_label=VALUES(role_label),status="active",can_view_pos=VALUES(can_view_pos),can_view_invoices=VALUES(can_view_invoices),can_upload_documents=VALUES(can_upload_documents)')->execute([(int)$_POST['supplier_id'],(int)$_POST['user_id'],trim((string)($_POST['role_label']??'Vendor User')),!empty($_POST['can_view_pos'])?1:0,!empty($_POST['can_view_invoices'])?1:0,!empty($_POST['can_upload_documents'])?1:0]);
      flash('success','Vendor access assigned.');
    }
    logActivity($pdo,'Vendor Portal','vendor_access_saved','Vendor portal access updated.','supplier',(int)($_POST['supplier_id']??0));
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'vendor-access']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/vendor-access.php');
}
