<?php
$pageTitle='RFQ Quote Comparison';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('rfq_management');
$pdo=getDB();
$id=(int)($_GET['id']??($_POST['id']??0));
$stmt=$pdo->prepare('SELECT * FROM '.table('rfqs').' WHERE id=? LIMIT 1');
$stmt->execute([$id]);$rfq=$stmt->fetch();
if(!$rfq){flash('error','RFQ not found.');redirect(ADMIN_URL.'/erp/rfqs.php');}
enforceScopeAllowed($pdo,(int)($rfq['company_id']??0),(int)($rfq['branch_id']??0),(int)($rfq['warehouse_id']??0),false);
if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['action']??'')==='award'){
  $quoteId=(int)($_POST['quote_id']??0);
  $pdo->beginTransaction();
  try{$poId=convertAwardedRfqQuoteToPurchaseOrder($pdo,$quoteId);$pdo->commit();flash('success','Supplier quote awarded and purchase order created.');redirect(ADMIN_URL.'/erp/view-purchase-order.php?id='.$poId);}catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());redirect(ADMIN_URL.'/erp/rfq-comparison.php?id='.$id);}
}
$items=$pdo->prepare('SELECT * FROM '.table('rfq_items').' WHERE rfq_id=? ORDER BY id ASC');$items->execute([$id]);$rfqItems=$items->fetchAll();
$quotes=$pdo->prepare('SELECT q.*,s.supplier_code,s.company_name FROM '.table('rfq_supplier_quotes').' q LEFT JOIN '.table('suppliers').' s ON s.id=q.supplier_id WHERE q.rfq_id=? ORDER BY q.rank_score DESC,q.total_amount ASC');$quotes->execute([$id]);$quoteRows=$quotes->fetchAll();
$itemQuotes=[];
if($quoteRows){
  $quoteIds=array_column($quoteRows,'id');$placeholders=implode(',',array_fill(0,count($quoteIds),'?'));
  $lineStmt=$pdo->prepare('SELECT * FROM '.table('rfq_supplier_quote_items').' WHERE rfq_supplier_quote_id IN ('.$placeholders.')');
  $lineStmt->execute($quoteIds);
  foreach($lineStmt->fetchAll() as $line){$itemQuotes[(int)$line['rfq_item_id']][(int)$line['rfq_supplier_quote_id']]=$line;}
}
include dirname(__DIR__).'/header.php';
?>
