<?php
$pageTitle='Sales Pipeline';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('sales_pipeline');
$pdo=getDB();
$scope=operationalScope($pdo);$scopeOptions=scopeSelectOptions($pdo);
$stages=$pdo->query('SELECT * FROM '.table('sales_pipeline_stages').' WHERE status="active" ORDER BY sort_order')->fetchAll();
$leads=$pdo->query('SELECT id,name,company,estimated_value,probability FROM '.table('crm_leads').' WHERE converted_customer_id IS NULL ORDER BY created_at DESC LIMIT 300')->fetchAll();
$customers=$pdo->query('SELECT id,customer_code,company_name,contact_name FROM '.table('customers').' WHERE status="active" ORDER BY company_name,contact_name LIMIT 300')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create'){
      $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)setting('default_warehouse_id','0'),'location_id'=>(int)setting('default_location_id','0')];
      $number=nextScopedDocumentNumber($pdo,'sales_opportunity',setting('sales_opportunity_prefix','OPP'),$scope);
      $value=max(0,(float)($_POST['value_amount']??0));$prob=max(0,min(100,(int)($_POST['probability']??0)));$weighted=round($value*$prob/100,2);
      $stmt=$pdo->prepare('INSERT INTO '.table('sales_opportunities').' (company_id,branch_id,opportunity_number,lead_id,customer_id,stage_id,owner_user_id,title,source,value_amount,probability,weighted_value,expected_close_date,status,next_follow_up,notes) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,"open",?,?)');
      $user=currentUser();
      $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,$number,(int)($_POST['lead_id']??0)?:null,(int)($_POST['customer_id']??0)?:null,(int)($_POST['stage_id']??0)?:null,(int)($user['id']??0)?:null,trim((string)$_POST['title']),trim((string)$_POST['source']),$value,$prob,$weighted,trim((string)($_POST['expected_close_date']??''))?:null,trim((string)($_POST['next_follow_up']??''))?:null,trim((string)($_POST['notes']??''))]);
      flash('success','Opportunity created.');
    }elseif($action==='move'){
      $id=(int)$_POST['id'];$stageId=(int)$_POST['stage_id'];
      $stage=$pdo->prepare('SELECT * FROM '.table('sales_pipeline_stages').' WHERE id=? LIMIT 1');$stage->execute([$stageId]);$stageRow=$stage->fetch();
      if(!$stageRow){throw new RuntimeException('Stage not found.');}
      $status=!empty($stageRow['is_won'])?'won':(!empty($stageRow['is_lost'])?'lost':'open');
      $pdo->prepare('UPDATE '.table('sales_opportunities').' SET stage_id=?,probability=?,weighted_value=ROUND(value_amount*?/100,2),status=?,last_activity_at=NOW() WHERE id=?')->execute([$stageId,(int)$stageRow['probability'],(int)$stageRow['probability'],$status,$id]);
      flash('success','Opportunity stage updated.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'sales-pipeline']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/sales-pipeline.php');
}
$opps=$pdo->query('SELECT o.*,s.stage_name,l.name lead_name,c.customer_code,c.company_name,c.contact_name FROM '.table('sales_opportunities').' o LEFT JOIN '.table('sales_pipeline_stages').' s ON s.id=o.stage_id LEFT JOIN '.table('crm_leads').' l ON l.id=o.lead_id LEFT JOIN '.table('customers').' c ON c.id=o.customer_id ORDER BY o.created_at DESC LIMIT 250')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
