lass="col-6"><label class="form-label">Value</label><input class="form-control" type="number" step="0.01" name="value_amount" value="0"></div><div class="col-6"><label class="form-label">Probability %</label><input class="form-control" type="number" min="0" max="100" name="probability" value="30"></div></div><label class="form-label mt-2">Expected Close</label><input class="form-control mb-2" type="date" name="expected_close_date"><label class="form-label">Next Follow-up</label><input class="form-control mb-2" type="date" name="next_follow_up"><label class="form-label">Source</label><input class="form-control mb-2" name="source"><label class="form-label">Notes</label><textarea class="form-control mb-3" name="notes" rows="3"></textarea><button class="btn btn-brand w-100">Create Opportunity</button></form></div>
