option></select><textarea class="form-control mb-2" name="finding_notes" rows="3" placeholder="Finding / evidence notes"></textarea><label class="form-label">Due Date</label><input class="form-control mb-3" type="date" name="due_date"><button class="btn btn-outline-primary w-100">Record Test</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Controls</h2><table class="table align-middle"><thead><tr><th>Control</th><th>Category</th><th>Risk</th><th>Frequency</th><th>Owner</th><th>Open Findings</th></tr></thead><tbody><?php foreach($controls as $c): ?><tr><td><strong><?php echo esc($c['control_code']); ?></strong><div class="small text-secondary"><?php echo esc($c['control_name']); ?></div></td><td><?php echo esc($c['category']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['risk_level']==='high'?'fail':($c['risk_level']==='medium'?'warning':'ok'))); ?>"><?php echo esc($c['risk_level']); ?></span></td><td><?php echo esc($c['frequency']); ?></td><td><?php echo esc($c['owner_email']?:'—'); ?></td><td><?php echo (int)$c['open_findings']; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Findings</h2><table class="table align-middle"><thead><tr><th>Date</th><th>Control</th><th>Result</th><th>Severity</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($findings as $f): ?><tr><td><?php echo esc($f['test_date']); ?></td><td><strong><?php echo esc($f['control_code']); ?></strong><div class="small text-secondary"><?php echo esc($f['finding_notes']); ?></div></td><td><span class="badge bg-<?php echo esc(statusTone($f['result'])); ?>"><?php echo esc($f['result']); ?></span></td><td><?php echo esc($f['severity']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($f['remediation_status'])); ?>"><?php echo esc($f['remediation_status']); ?></span></td><td><?php if($f['remediation_status']!=='closed'): ?><form method="post"><input type="hidden" name="action" value="close_finding"><input type="hidden" name="id" value="<?php echo (int)$f['id']; ?>"><button class="btn btn-sm btn-outline-success">Close</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$findings): ?><tr><td colspan="6" class="text-secondary">No findings yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
