  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_schedule'){
      if(setting('report_schedule_enabled','1')!=='1'){throw new RuntimeException('Report scheduling is disabled in settings.');}
      $code=nextScopedDocumentNumber($pdo,'report_schedule',setting('report_schedule_prefix','RSC'),operationalScope($pdo));$user=currentUser();
      $pdo->prepare('INSERT INTO '.table('report_schedules').' (saved_report_id,schedule_code,schedule_name,frequency,format,recipient_emails,next_run_at,status,created_by) VALUES (?,?,?,?,?,?,?,"active",?)')->execute([(int)$_POST['saved_report_id'],$code,trim((string)$_POST['schedule_name']),trim((string)$_POST['frequency']),trim((string)$_POST['format']),trim((string)$_POST['recipient_emails'],),trim((string)$_POST['next_run_at'])?:null,(int)($user['id']??0)?:null]);
      flash('success','Report schedule created.');
    }elseif($action==='run_schedule'){$result=runReportSchedule($pdo,(int)$_POST['schedule_id']);flash('success','Schedule run '.$result['run_number'].' completed with '.$result['rows'].' rows.');}
    elseif($action==='toggle'){$pdo->prepare('UPDATE '.table('report_schedules').' SET status=CASE WHEN status="active" THEN "inactive" ELSE "active" END WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Schedule status changed.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'scheduled-reports']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/scheduled-reports.php');
}
$schedules=$pdo->query('SELECT s.*,r.report_code,r.report_name,r.report_type FROM '.table('report_schedules').' s LEFT JOIN '.table('saved_reports').' r ON r.id=s.saved_report_id ORDER BY s.created_at DESC LIMIT 150')->fetchAll();
$runs=$pdo->query('SELECT rr.*,s.schedule_code,s.schedule_name FROM '.table('report_schedule_runs').' rr LEFT JOIN '.table('report_schedules').' s ON s.id=rr.report_schedule_id ORDER BY rr.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
