    if($action==='dispatch'){
      createFieldDispatch($pdo,(int)$_POST['job_card_id'],(int)$_POST['technician_user_id'],trim((string)$_POST['dispatch_date']),trim((string)$_POST['start_time']),trim((string)$_POST['service_address']));
