      $pdo->prepare('INSERT INTO '.table('field_service_routes').' (route_number,technician_user_id,route_date,route_name,start_location,end_location,status,notes) VALUES (?,?,?,?,?,?, "planned", ?)')->execute([$number,(int)$_POST['technician_user_id'],trim((string)$_POST['route_date']),trim((string)$_POST['route_name']),trim((string)$_POST['start_location']),trim((string)$_POST['end_location']),trim((string)$_POST['notes'])]);
      flash('success','Route created.');
    }elseif($action==='route_stop'){
      $pdo->prepare('INSERT INTO '.table('field_service_route_stops').' (field_service_route_id,job_card_id,field_service_dispatch_id,stop_order,eta,status,notes) VALUES (?,?,?,?,?,"planned",?)')->execute([(int)$_POST['route_id'],(int)$_POST['job_card_id'],(int)($_POST['dispatch_id']??0)?:null,(int)$_POST['stop_order'],trim((string)$_POST['eta'])?:null,trim((string)$_POST['notes'])]);
      flash('success','Route stop added.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'field-dispatch']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/field-dispatch.php');
}
$dispatches=$pdo->query('SELECT d.*,jc.job_card_number,jc.customer_name,jc.plate_number,u.email technician_email FROM '.table('field_service_dispatches').' d LEFT JOIN '.table('job_cards').' jc ON jc.id=d.job_card_id LEFT JOIN '.table('users').' u ON u.id=d.technician_user_id ORDER BY d.dispatch_date DESC,d.created_at DESC LIMIT 250')->fetchAll();
$routes=$pdo->query('SELECT r.*,u.email technician_email,(SELECT COUNT(*) FROM '.table('field_service_route_stops').' s WHERE s.field_service_route_id=r.id) stop_count FROM '.table('field_service_routes').' r LEFT JOIN '.table('users').' u ON u.id=r.technician_user_id ORDER BY r.route_date DESC,r.created_at DESC LIMIT 80')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
