      $pdo->prepare('INSERT INTO '.table('technician_checklists').' (checklist_code,checklist_name,job_type,status) VALUES (?,?,?,"active")')->execute([$code,trim((string)$_POST['checklist_name']),trim((string)$_POST['job_type'])]);
