        'admin/erp/bom.php' => <<<'P18_BOM'
<?php
$pageTitle='BOM Management';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('bom_management');
$pdo=getDB();
$products=[];$routings=[];$pageWarning='';
try{$products=$pdo->query('SELECT id,sku,name,COALESCE(NULLIF(average_cost,0), NULLIF(cost_price,0), 0) AS cost,price,stock FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();}catch(Throwable $e){$pageWarning=$e->getMessage();}
try{$routings=$pdo->query('SELECT * FROM '.table('manufacturing_routings').' WHERE status="active" ORDER BY routing_name')->fetchAll();}catch(Throwable $e){$pageWarning=$pageWarning?:$e->getMessage();}
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_bom'){
      $number=nextScopedDocumentNumber($pdo,'manufacturing_bom',setting('manufacturing_bom_prefix','BOM'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('bill_of_materials').' (bom_number,bom_name,finished_product_id,version_no,quantity,status,routing_id,notes) VALUES (?,?,?,?,?,"draft",?,?)')->execute([$number,trim((string)$_POST['bom_name']),(int)$_POST['finished_product_id'],trim((string)$_POST['version_no']),max(0.0001,(float)$_POST['quantity']),(int)$_POST['routing_id']?:null,trim((string)$_POST['notes'])]);
      flash('success','BOM created.');
    }elseif($action==='add_line'){
      $productId=(int)$_POST['component_product_id'];$qty=max(0.0001,(float)$_POST['quantity']);$waste=max(0,(float)$_POST['wastage_percent']);
      $p=$pdo->prepare('SELECT COALESCE(NULLIF(average_cost,0), NULLIF(cost_price,0), 0) FROM '.table('products').' WHERE id=?');$p->execute([$productId]);$unit=(float)$p->fetchColumn();
      $lineCost=$qty*(1+$waste/100)*$unit;
      $pdo->prepare('INSERT INTO '.table('bom_lines').' (bill_of_material_id,component_product_id,component_type,quantity,wastage_percent,unit_cost,line_cost,notes) VALUES (?,?,?,?,?,?,?,?)')->execute([(int)$_POST['bom_id'],$productId,trim((string)$_POST['component_type']),$qty,$waste,$unit,$lineCost,trim((string)$_POST['notes'])]);
      flash('success','BOM line added.');
    }elseif($action==='approve'){
      $pdo->prepare('UPDATE '.table('bill_of_materials').' SET status="approved" WHERE id=?')->execute([(int)$_POST['bom_id']]);flash('success','BOM approved.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'bom']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/bom.php');
}
$boms=[];$lines=[];
try{$boms=$pdo->query('SELECT b.*,p.name product_name FROM '.table('bill_of_materials').' b LEFT JOIN '.table('products').' p ON p.id=b.finished_product_id ORDER BY b.created_at DESC LIMIT 100')->fetchAll();}catch(Throwable $e){$pageWarning=$pageWarning?:$e->getMessage();}
try{$lines=$pdo->query('SELECT l.*,b.bom_number,p.name component_name,p.sku FROM '.table('bom_lines').' l LEFT JOIN '.table('bill_of_materials').' b ON b.id=l.bill_of_material_id LEFT JOIN '.table('products').' p ON p.id=l.component_product_id ORDER BY l.created_at DESC LIMIT 150')->fetchAll();}catch(Throwable $e){$pageWarning=$pageWarning?:$e->getMessage();}
include dirname(__DIR__).'/header.php';
?>
<?php if(!empty($pageWarning)): ?><div class="alert alert-warning">BOM module warning: <?php echo esc($pageWarning); ?>. Run the latest installer/update if manufacturing tables are missing.</div><?php endif; ?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Bill of Materials</div><h2 class="h4 mb-1">BOM Management</h2><p class="text-secondary mb-0">Create product recipes, components, wastage, routing, and BOM cost basis.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/manufacturing-costing.php">Cost Rollup</a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_bom"><h2 class="h5 mb-3">Create BOM</h2><input class="form-control mb-2" name="bom_name" placeholder="BOM name"><label class="form-label">Finished Product</label><select class="form-select mb-2" name="finished_product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="version_no" value="1.0"><input class="form-control mb-2" type="number" step="0.0001" name="quantity" value="1"><label class="form-label">Routing</label><select class="form-select mb-2" name="routing_id"><option value="0">No routing</option><?php foreach($routings as $r): ?><option value="<?php echo (int)$r['id']; ?>"><?php echo esc($r['routing_code'].' · '.$r['routing_name']); ?></option><?php endforeach; ?></select><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create BOM</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="add_line"><h2 class="h5 mb-3">Add Component</h2><label class="form-label">BOM</label><select class="form-select mb-2" name="bom_id"><?php foreach($boms as $b): ?><option value="<?php echo (int)$b['id']; ?>"><?php echo esc($b['bom_number'].' · '.$b['bom_name']); ?></option><?php endforeach; ?></select><label class="form-label">Component</label><select class="form-select mb-2" name="component_product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name'].' · Cost '.money($p['cost'])); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="component_type"><option value="material">Material</option><option value="service">Service</option><option value="packaging">Packaging</option></select><input class="form-control mb-2" type="number" step="0.0001" name="quantity" value="1"><input class="form-control mb-2" type="number" step="0.01" name="wastage_percent" placeholder="Wastage %"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Add Line</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">BOMs</h2><table class="table align-middle"><thead><tr><th>BOM</th><th>Finished Product</th><th>Qty</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($boms as $b): $cost=bomCostSummary($pdo,(int)$b['id']); ?><tr><td><strong><?php echo esc($b['bom_number']); ?></strong><div class="small text-secondary"><?php echo esc($b['bom_name']); ?> · Cost <?php echo money($cost['total']); ?></div></td><td><?php echo esc($b['product_name']); ?></td><td><?php echo number_format((float)$b['quantity'],4); ?></td><td><span class="badge bg-<?php echo esc(statusTone($b['status'])); ?>"><?php echo esc($b['status']); ?></span></td><td><?php if($b['status']!=='approved'): ?><form method="post"><input type="hidden" name="action" value="approve"><input type="hidden" name="bom_id" value="<?php echo (int)$b['id']; ?>"><button class="btn btn-sm btn-success">Approve</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Recent Components</h2><table class="table"><thead><tr><th>BOM</th><th>Component</th><th>Qty</th><th>Wastage</th><th>Line Cost</th></tr></thead><tbody><?php foreach($lines as $l): ?><tr><td><?php echo esc($l['bom_number']); ?></td><td><?php echo esc($l['sku'].' · '.$l['component_name']); ?></td><td><?php echo number_format((float)$l['quantity'],4); ?></td><td><?php echo number_format((float)$l['wastage_percent'],2); ?>%</td><td><?php echo money($l['line_cost']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
