  try{
    $action=(string)($_POST['action']??'');
    if($action==='center'){
      $code=trim((string)$_POST['center_code']); if($code===''){$code=nextScopedDocumentNumber($pdo,'work_center',setting('work_center_prefix','WC'),operationalScope($pdo));}
      $pdo->prepare('INSERT INTO '.table('manufacturing_work_centers').' (center_code,center_name,center_type,hourly_rate,capacity_hours_per_day,status,notes) VALUES (?,?,?,?,?,"active",?)')->execute([$code,trim((string)$_POST['center_name']),trim((string)$_POST['center_type']),max(0,(float)$_POST['hourly_rate']),max(0,(float)$_POST['capacity_hours_per_day']),trim((string)$_POST['notes'])]);
      flash('success','Work center created.');
    }elseif($action==='routing'){
      $code=trim((string)$_POST['routing_code']);
      $pdo->prepare('INSERT INTO '.table('manufacturing_routings').' (routing_code,routing_name,product_id,status,notes) VALUES (?,?,?,"active",?)')->execute([$code,trim((string)$_POST['routing_name']),(int)$_POST['product_id']?:null,trim((string)$_POST['notes'])]);
      flash('success','Routing created.');
    }elseif($action==='step'){
      $pdo->prepare('INSERT INTO '.table('manufacturing_routing_steps').' (manufacturing_routing_id,step_number,work_center_id,operation_name,standard_minutes,labor_rate,notes) VALUES (?,?,?,?,?,?,?)')->execute([(int)$_POST['routing_id'],(int)$_POST['step_number'],(int)$_POST['work_center_id']?:null,trim((string)$_POST['operation_name']),max(0,(float)$_POST['standard_minutes']),max(0,(float)$_POST['labor_rate']),trim((string)$_POST['notes'])]);
      flash('success','Routing step added.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'work-centers']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/work-centers.php');
}
$centers=$pdo->query('SELECT * FROM '.table('manufacturing_work_centers').' ORDER BY center_code')->fetchAll();
$routings=$pdo->query('SELECT r.*,p.name product_name FROM '.table('manufacturing_routings').' r LEFT JOIN '.table('products').' p ON p.id=r.product_id ORDER BY r.created_at DESC')->fetchAll();
$steps=$pdo->query('SELECT s.*,r.routing_code,w.center_code FROM '.table('manufacturing_routing_steps').' s LEFT JOIN '.table('manufacturing_routings').' r ON r.id=s.manufacturing_routing_id LEFT JOIN '.table('manufacturing_work_centers').' w ON w.id=s.work_center_id ORDER BY r.routing_code,s.step_number')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
