if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='session'){createStockCountSession($pdo,(int)$_POST['warehouse_id'],0,0,trim((string)$_POST['count_type']),trim((string)$_POST['notes']));flash('success','Stock count session started.');}elseif($action==='line'){addStockCountLine($pdo,(int)$_POST['session_id'],(int)$_POST['product_id'],max(0,(float)$_POST['counted_qty']),trim((string)$_POST['notes']));flash('success','Count line added.');}elseif($action==='adjustment'){createInventoryAdjustmentFromCount($pdo,(int)$_POST['session_id']);flash('success','Adjustment request created from variance.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'stock-counts']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/stock-counts.php');}
$lines=$pdo->query('SELECT l.*,s.count_number,p.sku,p.name FROM '.table('stock_count_lines').' l LEFT JOIN '.table('stock_count_sessions').' s ON s.id=l.stock_count_session_id LEFT JOIN '.table('products').' p ON p.id=l.product_id ORDER BY l.created_at DESC LIMIT 150')->fetchAll();
