tus</th><th>Adjustment</th></tr></thead><tbody><?php foreach($sessions as $s): ?><tr><td><strong><?php echo esc($s['count_number']); ?></strong></td><td><?php echo esc($s['warehouse_name']); ?></td><td><?php echo esc($s['count_type']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td><td><form method="post"><input type="hidden" name="action" value="adjustment"><input type="hidden" name="session_id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-success">Create Adjustment</button></form></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Count Lines</h2><table class="table"><thead><tr><th>Session</th><th>Product</th><th>System</th><th>Counted</th><th>Variance</th><th>Value</th></tr></thead><tbody><?php foreach($lines as $l): ?><tr><td><?php echo esc($l['count_number']); ?></td><td><?php echo esc($l['sku'].' · '.$l['name']); ?></td><td><?php echo number_format((float)$l['system_qty'],4); ?></td><td><?php echo number_format((float)$l['counted_qty'],4); ?></td><td><?php echo number_format((float)$l['variance_qty'],4); ?></td><td><?php echo money($l['variance_value']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
