<?php
$pageTitle='Inventory Adjustments';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('inventory_adjustments');
$pdo=getDB();
$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();$products=$pdo->query('SELECT id,sku,name,COALESCE(NULLIF(average_cost,0), NULLIF(cost_price,0), 0) AS cost FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='request'){$num=nextScopedDocumentNumber($pdo,'inventory_adjustment',setting('inventory_adjustment_prefix','ADJ'),operationalScope($pdo));$user=currentUser();$pdo->prepare('INSERT INTO '.table('inventory_adjustment_requests').' (adjustment_number,warehouse_id,reason,status,requested_by,requested_at,notes) VALUES (?,?,?,"draft",?,NOW(),?)')->execute([$num,(int)$_POST['warehouse_id'],trim((string)$_POST['reason']),(int)($user['id']??0)?:null,trim((string)$_POST['notes'])]);flash('success','Adjustment request created.');}elseif($action==='line'){$cost=productDefaultCost($pdo,(int)$_POST['product_id']);$qty=(float)$_POST['adjustment_qty'];$pdo->prepare('INSERT INTO '.table('inventory_adjustment_lines').' (inventory_adjustment_request_id,product_id,adjustment_qty,unit_cost,total_value,notes) VALUES (?,?,?,?,?,?)')->execute([(int)$_POST['request_id'],(int)$_POST['product_id'],$qty,$cost,$qty*$cost,trim((string)$_POST['notes'])]);flash('success','Adjustment line added.');}elseif($action==='post'){postInventoryAdjustment($pdo,(int)$_POST['request_id']);flash('success','Adjustment posted to stock.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'inventory-adjustments']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/inventory-adjustments.php');}
$requests=$pdo->query('SELECT a.*,w.warehouse_name FROM '.table('inventory_adjustment_requests').' a LEFT JOIN '.table('warehouses').' w ON w.id=a.warehouse_id ORDER BY a.created_at DESC LIMIT 100')->fetchAll();
$lines=$pdo->query('SELECT l.*,a.adjustment_number,p.sku,p.name FROM '.table('inventory_adjustment_lines').' l LEFT JOIN '.table('inventory_adjustment_requests').' a ON a.id=l.inventory_adjustment_request_id LEFT JOIN '.table('products').' p ON p.id=l.product_id ORDER BY l.created_at DESC LIMIT 120')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Stock Correction</div><h2 class="h4 mb-1">Inventory Adjustments</h2><p class="text-secondary mb-0">Create stock adjustment requests, add variance lines, and post approved stock movements.</p></div></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="request"><h2 class="h5 mb-3">New Adjustment</h2><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="reason" placeholder="Reason"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Request</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="line"><h2 class="h5 mb-3">Add Line</h2><select class="form-select mb-2" name="request_id"><?php foreach($requests as $r): ?><option value="<?php echo (int)$r['id']; ?>"><?php echo esc($r['adjustment_number']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" step="0.0001" name="adjustment_qty" placeholder="+/- quantity"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Add Line</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><table class="table"><thead><tr><th>Adjustment</th><th>Warehouse</th><th>Reason</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($requests as $r): ?><tr><td><strong><?php echo esc($r['adjustment_number']); ?></strong></td><td><?php echo esc($r['warehouse_name']); ?></td><td><?php echo esc($r['reason']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td><td><?php if($r['status']!=='posted'): ?><form method="post"><input type="hidden" name="action" value="post"><input type="hidden" name="request_id" value="<?php echo (int)$r['id']; ?>"><button class="btn btn-sm btn-success">Post</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Lines</h2><table class="table"><thead><tr><th>Adjustment</th><th>Product</th><th>Qty</th><th>Value</th></tr></thead><tbody><?php foreach($lines as $l): ?><tr><td><?php echo esc($l['adjustment_number']); ?></td><td><?php echo esc($l['sku'].' · '.$l['name']); ?></td><td><?php echo number_format((float)$l['adjustment_qty'],4); ?></td><td><?php echo money($l['total_value']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
