t_qty'],4); ?></td><td><?php echo number_format((float)$s['recommended_qty'],4); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td><td><?php if($s['status']==='open'): ?><form method="post"><input type="hidden" name="action" value="close"><input type="hidden" name="id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-outline-success">Close</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Rules</h2><table class="table"><thead><tr><th>Rule</th><th>Product</th><th>Warehouse</th><th>Min</th><th>Max</th><th>Reorder</th></tr></thead><tbody><?php foreach($rules as $r): ?><tr><td><strong><?php echo esc($r['rule_code']); ?></strong></td><td><?php echo esc($r['sku'].' · '.$r['name']); ?></td><td><?php echo esc($r['warehouse_name']); ?></td><td><?php echo number_format((float)$r['min_qty'],4); ?></td><td><?php echo number_format((float)$r['max_qty'],4); ?></td><td><?php echo number_format((float)$r['reorder_qty'],4); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
