 table-responsive mb-4"><h2 class="h5 mb-3">Dispatches</h2><table class="table"><thead><tr><th>Dispatch</th><th>Packing</th><th>Warehouse</th><th>Carrier</th><th>Status</th></tr></thead><tbody><?php foreach($dispatches as $d): ?><tr><td><strong><?php echo esc($d['dispatch_number']); ?></strong><div class="small text-secondary"><?php echo esc($d['tracking_number']); ?></div></td><td><?php echo esc($d['packing_number']); ?></td><td><?php echo esc($d['warehouse_name']); ?></td><td><?php echo esc($d['carrier']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Dispatch Items</h2><table class="table"><thead><tr><th>Dispatch</th><th>Product</th><th>Qty</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['dispatch_number']); ?></td><td><?php echo esc($i['sku'].' · '.$i['name']); ?></td><td><?php echo number_format((float)$i['dispatch_qty'],4); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
