 ?></strong><div class="small text-secondary"><?php echo esc($e['event_message']); ?></div></td><td><?php echo number_format((float)$e['metric_value'],2); ?></td><td><?php echo number_format((float)$e['threshold_value'],2); ?></td><td><span class="badge bg-<?php echo esc(statusTone($e['status'])); ?>"><?php echo esc($e['status']); ?></span></td><td><?php if($e['status']!=='closed'): ?><form method="post"><input type="hidden" name="action" value="close"><input type="hidden" name="id" value="<?php echo (int)$e['id']; ?>"><button class="btn btn-sm btn-success">Close</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
