    elseif($action==='mark_done'){$pdo->prepare('UPDATE '.table('marketplace_sync_queue').' SET status="completed",last_attempt_at=NOW(),attempt_count=attempt_count+1 WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Marketplace sync item completed.');}
