        'admin/erp/commercial-packaging.php' => <<<'P35_COMMERCIAL_PACKAGING'
<?php
$pageTitle='Commercial Packaging';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('commercial_packaging');
$pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'package');
    if($action==='install'){p35InstallDefaults($pdo);flash('success','Commercial package defaults installed.');}
    elseif($action==='feature'){p35AddPackageFeature($pdo,(int)$_POST['commercial_package_id'],trim((string)$_POST['feature_group']),trim((string)$_POST['feature_name']),trim((string)$_POST['feature_description']),trim((string)$_POST['included_limit']),(int)$_POST['sort_order']);flash('success','Package feature added.');}
    else{p35CreateCommercialPackage($pdo,trim((string)$_POST['package_name']),trim((string)$_POST['package_type']),trim((string)$_POST['target_customer']),trim((string)$_POST['billing_cycle']),(float)$_POST['base_price'],trim((string)$_POST['currency']),(int)$_POST['implementation_days'],trim((string)$_POST['description']));flash('success','Commercial package created.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'commercial-packaging']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/commercial-packaging.php');
}
$packages=$pdo->query('SELECT * FROM '.table('commercial_packages').' ORDER BY base_price ASC,package_name')->fetchAll();
$features=$pdo->query('SELECT f.*,p.package_name FROM '.table('commercial_package_features').' f LEFT JOIN '.table('commercial_packages').' p ON p.id=f.commercial_package_id ORDER BY p.base_price,f.sort_order LIMIT 300')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
