get</th><th>Price</th><th>Implementation</th></tr></thead><tbody><?php foreach($packages as $p): ?><tr><td><strong><?php echo esc($p['package_number']); ?></strong><div class="small text-secondary"><?php echo esc($p['package_name'].' · '.$p['description']); ?></div></td><td><?php echo esc($p['target_customer']); ?></td><td><?php echo esc($p['currency']); ?> <?php echo number_format((float)$p['base_price'],2); ?></td><td><?php echo (int)$p['implementation_days']; ?> days</td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Package Features</h2><table class="table"><tbody><?php foreach($features as $f): ?><tr><td><strong><?php echo esc($f['package_name']); ?></strong><div class="small text-secondary"><?php echo esc($f['feature_group'].' · '.$f['feature_name'].' · '.$f['included_limit']); ?></div></td></tr><?php endforeach; ?></tbody></table></div></div></div>
