$stmt=$pdo->prepare('SELECT q.*,c.customer_code FROM ' . table('quotations') . ' q LEFT JOIN ' . table('customers') . ' c ON c.id=q.customer_id'.$where.' ORDER BY q.created_at DESC,q.id DESC');
