                <div class="col-md-4"><div class="data-card"><div class="erp-kicker">Supplier Contact</div><div class="fw-semibold"><?php echo esc($po['contact_name'] ?: '—'); ?></div><div class="small-muted"><?php echo esc($po['email'] ?: ''); ?></div></div></div>
