<script>
(function(){
  const form = document.getElementById('bundleInstallerForm');
  if(!form) return;
  const moduleBoxes = Array.from(form.querySelectorAll('input[name="enabled_modules[]"]'));
  const bundleRadios = Array.from(form.querySelectorAll('input[name="module_bundle"]'));
  const businessRadios = Array.from(form.querySelectorAll('input[name="business_type"]'));

  function applyBundle(radio){
    if(!radio || radio.value === 'custom') return;
    const modules = (radio.dataset.modules || '').split(',').filter(Boolean);
    moduleBoxes.forEach(box => { box.checked = modules.includes(box.value); });
  }

  bundleRadios.forEach(radio => {
    radio.addEventListener('change', () => applyBundle(radio));
  });

  moduleBoxes.forEach(box => {
    box.addEventListener('change', () => {
      const custom = bundleRadios.find(r => r.value === 'custom');
      if(custom) custom.checked = true;
    });
  });

  businessRadios.forEach(radio => {
    radio.addEventListener('change', () => {
      const recommended = radio.dataset.recommendedBundle || 'starter_commerce';
      const bundle = bundleRadios.find(r => r.value === recommended);
      if(bundle){
        bundle.checked = true;
        applyBundle(bundle);
      }
    });
  });
})();
</script>
